ALTER TABLE public.instructor_warnings DROP CONSTRAINT IF EXISTS instructor_warnings_warning_type_check;
ALTER TABLE public.instructor_warnings ADD CONSTRAINT instructor_warnings_warning_type_check CHECK (warning_type = ANY (ARRAY['no_quiz'::text, 'no_assignment'::text, 'no_attendance'::text, 'no_evaluation'::text, 'no_reply'::text, 'late_grading'::text, 'behavior'::text, 'non_compliance'::text, 'poor_performance'::text, 'attendance'::text, 'late_submission'::text, 'other'::text]));